import axios from 'axios'
import type {
  AxiosError,
  AxiosResponse,
  InternalAxiosRequestConfig,
  AxiosRequestConfig,
} from 'axios'
import { Message } from '@arco-design/web-react'
import i18n from 'i18next'
import { getLanguage } from '@common/utils/localStorage'
import { apiBaseURL, appUserType } from '@common/constants/env'
import { contractorAuthStorage } from '@/pages/Contractor/contractorAuth'
import { history } from '@/store'

const NetworkErrorMessage = i18n.t('message:error.network')

const ErrorMessages: Record<number, string> = {
  400: 'Request error',
  401: i18n.t('message:error.401'),
  403: 'Access denied',
  404: 'Request address error',
  408: 'Request timeout',
  500: 'Server failure',
  501: 'Service not implemented',
  502: NetworkErrorMessage,
  503: 'Service unavailable',
  504: NetworkErrorMessage,
  505: 'HTTP versions are not supported',
}

const SUCCESS_CODES = [0, 40114]
const FREQUENT_LOGIN_CODE = '40101'

export const contractorService = axios.create({
  baseURL: apiBaseURL,
  timeout: 60000,
  headers: {
    userType: appUserType,
    'Content-Type': 'application/json;charset=utf-8',
  },
})

contractorService.interceptors.request.use(
  (config: InternalAxiosRequestConfig) => {
    const token = contractorAuthStorage.getToken()
    if (token) {
      config.headers.EToken = token
    }
    config.headers['language'] = getLanguage()
    return config
  },
  (error: AxiosError) => {
    return Promise.reject(error)
  },
)

contractorService.interceptors.response.use(
  (response: AxiosResponse) => {
    const { hideToast } = response.config.headers
    const { code, msg, data } = response.data

    if (response.config.responseType === 'blob') {
      return response
    }

    if (!SUCCESS_CODES.includes(Number(code))) {
      if (Number(code) === 400401) {
        history.replace('/contractor-login')
        return Promise.reject(new Error(msg))
      }

      if (hideToast) {
        if (code == FREQUENT_LOGIN_CODE) {
          const tempError = new Error(msg)
          ;(tempError as any).errorCode = FREQUENT_LOGIN_CODE
          return Promise.reject(tempError)
        }
        return Promise.reject(new Error(msg))
      }

      Message.error(msg)
      return Promise.reject(new Error(response.data))
    }

    return data
  },
  (error: AxiosError) => {
    if (error && error?.code === 'ECONNABORTED') {
      Message.error(error?.message)
      return Promise.reject(error)
    }

    const { status, data } = error.response as any
    const { msg } = data || ({} as any)
    const isToken = msg == 'Token会话不存在'
    const message = msg || ErrorMessages[status] || NetworkErrorMessage

    console.error('123',status ,message)

    if (status === 401 || isToken) {
      // 401 only redirects when token is truly missing; API-level 401 falls through to caller
      if (!contractorAuthStorage.getToken() || isToken) {
        history.replace('/contractor-login')
        return
      }
      return Promise.reject(error)
    } else if (status === 403) {
      history.replace('/403')
      return
    }

    Message.error(message)

    return Promise.reject(error)
  },
)

const contractorHttp = {
  request<T = any>(config: AxiosRequestConfig): Promise<T> {
    return contractorService.request(config)
  },

  get<T = any>(url: string, config?: AxiosRequestConfig): Promise<T> {
    return contractorService.get(url, config)
  },

  post<T = any>(
    url: string,
    data?: object,
    config?: AxiosRequestConfig,
  ): Promise<T> {
    return contractorService.post(url, data, config)
  },

  put<T = any>(
    url: string,
    data?: object,
    config?: AxiosRequestConfig,
  ): Promise<T> {
    return contractorService.put(url, data, config)
  },

  delete<T = any>(url: string, config?: AxiosRequestConfig): Promise<T> {
    return contractorService.delete(url, config)
  },
}

export default contractorHttp

