// packages/common/src/utils/localStorage.ts
import { LanguageEnum } from '@common/constants/language'
import {
  tokenStorageKey,
  languageStorageKey,
} from '@common/constants/localStorageKey'

export const getToken = () => {
  return window.localStorage.getItem(tokenStorageKey)
}

export const setToken = (token: string) => {
  window.localStorage.setItem(tokenStorageKey, token)
}

export const removeToken = () => {
  window.localStorage.removeItem(tokenStorageKey)
}

export const getLanguage: () => LanguageEnum = () => {
  return (window.localStorage.getItem(languageStorageKey) ||
    LanguageEnum.EN) as LanguageEnum
}

export const setLanguage = (language: LanguageEnum) => {
  window.localStorage.setItem(languageStorageKey, language)
}

export const redirectToLogin = () => {
  removeToken()
  window.location.replace('/contractor-login')
}
```

> `setRedirectStorage`、`getRedirectStorage`、`removeRedirectStorage` 是员工端专用逻辑，直接删除。`redirectStorageKey` 的 import 也一并去掉。

- [ ] **提交**

```bash
git add packages/common/src/utils/localStorage.ts
git commit -m "chore: simplify redirectToLogin to contractor-login, remove employee redirect helpers"
```

---

### Task 3：更新 common HTTP 拦截器

**文件：**
- 修改：`packages/common/src/service/request/index.ts`

- [ ] **修改请求头、新增 400401 处理、删除 console.error**

需要做三处改动：
1. 请求拦截器：`jToken` → `EToken`
2. 响应拦截器：在 `SUCCESS_CODES` 判断失败分支内，添加 `400401` 错误码处理
3. 错误拦截器：删除 `console.error(message)`

```typescript
// packages/common/src/service/request/index.ts
import {
  getLanguage,
  getToken,
  redirectToLogin,
} from '@common/utils/localStorage'
import { Message } from '@arco-design/web-react'
import axios from 'axios'
import i18n from 'i18next'

import {
  AxiosError,
  AxiosResponse,
  InternalAxiosRequestConfig,
  AxiosRequestConfig,
} from 'axios'

import { apiBaseURL, appUserType } from '@common/constants/env'

const NetworkErrorMessage = i18n.t('message:error.network')

const ErrorMessages: Record<number, string> = {
  400: 'Request error',
  401: i18n.t('message:error.401'),
  403: 'Access denied',
  404: 'Request address error',
  408: 'Request timeout',
  500: 'Server failure',
  501: 'Service not implemented',
  502: NetworkErrorMessage,
  503: 'Service unavailable',
  504: NetworkErrorMessage,
  505: 'HTTP versions are not supported',
}

const SUCCESS_CODES = [0, 40114]
const FREQUENT_LOGIN_CODE = '40101'

export const service = axios.create({
  baseURL: apiBaseURL,
  timeout: 60000,
  headers: {
    userType: appUserType,
    'Content-Type': 'application/json;charset=utf-8',
  },
})

service.interceptors.request.use(
  (config: InternalAxiosRequestConfig) => {
    const token = getToken()
    if (token) {
      config.headers.EToken = token
    }
    config.headers['language'] = getLanguage()
    return config
  },
  (error: AxiosError) => {
    return Promise.reject(error)
  },
)

service.interceptors.response.use(
  (response: AxiosResponse) => {
    const { hideToast } = response.config.headers
    const { code, msg, data } = response.data
    if (response.config.responseType === 'blob') {
      return response
    }

    if (!SUCCESS_CODES.includes(Number(code))) {
      if (Number(code) === 400401) {
        redirectToLogin()
        return Promise.reject(new Error(msg))
      }

      if (hideToast) {
        if (code == FREQUENT_LOGIN_CODE) {
          const tempError = new Error(msg)
          ;(tempError as any).errorCode = FREQUENT_LOGIN_CODE
          return Promise.reject(tempError)
        }
        return Promise.reject(new Error(msg))
      }

      Message.error(msg)
      return Promise.reject(new Error(response.data))
    }

    return data
  },
  (error: AxiosError) => {
    if (error && error?.code === 'ECONNABORTED') {
      Message.error(error?.message)
    } else {
      const { status, data } = error.response
      const { msg } = data || ({} as any)
      const isToken = msg == 'Token会话不存在'
      const message = msg || ErrorMessages[status] || NetworkErrorMessage

      if (status === 401 || isToken) {
        redirectToLogin()
        return
      } else if (status === 403) {
        window.location.href = '/403'
        return
      }

      Message.error(message)
      return Promise.reject(error)
    }
  },
)

const http = {
  request<T = any>(config: AxiosRequestConfig): Promise<T> {
    return service.request(config)
  },

  get<T = any>(url: string, config?: AxiosRequestConfig): Promise<T> {
    return service.get(url, config)
  },

  post<T = any>(
    url: string,
    data?: object,
    config?: AxiosRequestConfig,
  ): Promise<T> {
    return service.post(url, data, config)
  },

  put<T = any>(
    url: string,
    data?: object,
    config?: AxiosRequestConfig,
  ): Promise<T> {
    return service.put(url, data, config)
  },

  delete<T = any>(url: string, config?: AxiosRequestConfig): Promise<T> {
    return service.delete(url, config)
  },
}

export default http
```

