// src/pages/Contractor/hooks/useContractorLogout.ts
import { useCallback } from 'react'
import { logoutRedirectURL } from '@common/constants/env'
import { contractorLogout } from '@/service/apis/contractorPortal'
import { getToken, removeToken } from '@common/utils/localStorage'

const useContractorLogout = () => {
  return useCallback(() => {
    if (logoutRedirectURL) {
      const token = getToken() ?? ''
      removeToken()
      window.location.href = `${logoutRedirectURL}?jToken=${token}`
    } else {
      contractorLogout({}).finally(() => {
        removeToken()
        window.location.replace('/contractor-login')
      })
    }
  }, [])
}

export default useContractorLogout
