import { memo, useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { useNavigate, Outlet } from 'react-router-dom'
import { RouterState } from 'redux-first-history'
import { Layout } from '@arco-design/web-react'
import { AppDispatch, RootState } from '@/store'

import Header from './components/Header'
import CustomMenu from './components/Slider'
import './index.less'
import useLoadUserInfo from '@common/hooks/useLoadUserInfo'
import { IconMenuFold, IconMenuUnfold } from '@arco-design/web-react/icon'
import classNames from 'classnames'
import { useIsUserLogin } from '@common/hooks/useIsUserLogin'
import { UserState } from '@common/store/slices/user'
import { getRoleRoutePath } from '@common/utils/menu'
import { isCheckUserLoginInfo } from '@common/constants/env'
// import { changePageWrapperMinWidth } from '@/store/slices/global'
// import {
//   pageWrapperMinWidthWithSider,
//   pageWrapperMinWidth,
// } from '@/constants/common'

const Sider = Layout.Sider
const LayoutHeader = Layout.Header
const Content = Layout.Content

const classPrefix = 'layout'

function Container() {
  const [collapsed, setCollapsed] = useState(false)

  const navigate = useNavigate()
  const router = useSelector<RootState, RouterState>((state) => state.router)
  const { userRoleMenuList } = useSelector<RootState, UserState>(
    (state) => state.user,
  )

  const dispatch = useDispatch<AppDispatch>()

  useEffect(() => {
    if (router.location?.pathname === '/' && userRoleMenuList.length > 0) {
      // 拿到用户角色对应的路由后，自动跳转到有权限的第一个页面
      const path = getRoleRoutePath(userRoleMenuList)
      navigate(path, { replace: true })
    }
  }, [navigate, router.location?.pathname, userRoleMenuList])

  const toggleCollapsed = (collapsed: boolean) => {
    setCollapsed(collapsed)
  }

  useEffect(() => {
    // dispatch(
    //   changePageWrapperMinWidth(
    //     collapsed ? pageWrapperMinWidth : pageWrapperMinWidthWithSider,
    //   ),
    // )
  }, [collapsed, dispatch])

  //写静态页面的时候不需要登录信息
  if (isCheckUserLoginInfo) {
    useLoadUserInfo()
    const isLogin = useIsUserLogin()
    if (!isLogin) {
      return null
    }
  }

  return (
    <div className={classPrefix}>
      <Layout style={{ height: '100%' }}>
        <LayoutHeader>
          <Header showUserInfo />
        </LayoutHeader>
        <Layout style={{ overflow: 'hidden' }}>
          <Sider
            style={{ backgroundColor: '#fff' }}
            width={240}
            className={classNames(classPrefix + '__slider', {
              [classPrefix + '__slider--collapsed']: collapsed,
            })}
            collapsible
            trigger={
              collapsed ? (
                <div className={classPrefix + '__slider__menu-icon'}>
                  <IconMenuUnfold />
                </div>
              ) : (
                <div className={classPrefix + '__slider__menu-icon'}>
                  <IconMenuFold />
                </div>
              )
            }
            breakpoint='xl'
            collapsed={collapsed}
            onCollapse={toggleCollapsed}
          >
            <CustomMenu />
          </Sider>
          <Content className={classPrefix + '__content'}>
            <Outlet />
          </Content>
        </Layout>
      </Layout>
    </div>
  )
}

export default memo(Container)
